meta.script:
    async function generateFeed() {
      const params = new URLSearchParams(window.location.search);
      const showFilter = params.get("shows")?.split(',').map(s => s.trim().toLowerCase()) || null;

      const res = await fetch('dropout_feed.xml');
      const xmlText = await res.text();
      const parser = new DOMParser();
      const xml = parser.parseFromString(xmlText, "application/xml");

      const channel = xml.querySelector('channel');
      const items = Array.from(xml.querySelectorAll('item'));
      const filteredItems = showFilter
        ? items.filter(item => {
            const title = item.querySelector('title')?.textContent || '';
            return showFilter.some(show => title.toLowerCase().includes(`[${show}]`.toLowerCase()));
          })
        : items;

      const feed = `


  ${channel.querySelector('title')?.textContent}
  ${channel.querySelector('link')?.textContent}
  ${channel.querySelector('description')?.textContent}
  ${filteredItems.map(item => item.outerHTML).join('\n')}

`;

      document.open("application/rss+xml", "replace");
      document.write(feed);
      document.close();
    }
    generateFeed();
